def _parse_selections(self, text: str) -> Dict:
    result = {}
    tokens = text.split()
    i = 0
    while i < len(tokens):
        name = tokens[i]
        if i + 1 < len(tokens) and tokens[i + 1] == '{':
            # Find matching closing brace (track depth)
            close = self._find_matching_brace(tokens, i + 1)
            inner = ' '.join(tokens[i + 2:close])
            result[name] = self._parse_selections(inner)
            i = close + 1
        else:
            result[name] = None
            i += 1
    return result

def _find_matching_brace(self, tokens: List[str], open_idx: int) -> int:
    depth = 0
    for i in range(open_idx, len(tokens)):
        if tokens[i] == '{':
            depth += 1
        elif tokens[i] == '}':
            depth -= 1
            if depth == 0:
                return i
    raise ValueError('Unmatched brace in query')
